mapper.select:
SELECT x.id AS id, x.tenant_id AS tenantId, t.tenant_code AS tenantCode, t.name AS tenantName, x.user_id AS userId, u.username AS username, u.display_name AS userDisplayName, x.direction AS direction, x.delta AS delta, x.balance_before AS balanceBefore, x.balance_after AS balanceAfter, x.frozen_balance_before AS frozenBalanceBefore, x.frozen_balance_after AS frozenBalanceAfter, x.transaction_type AS transactionType, x.reservation_id AS reservationId, x.reason AS reason, x.operator_id AS operatorId, x.operator_name AS operatorName, x.created_at AS createdAt FROM credit_transaction x INNER JOIN user_account u ON u.id = x.user_id INNER JOIN tenant t ON t.id = x.tenant_id WHERE 1 = 1 AND x.tenant_id = #{tenantId} AND x.user_id = #{userId} AND x.direction = #{direction}
AND (u.username ILIKE CONCAT('%', #{keyword}, '%') OR u.display_name ILIKE CONCAT('%', #{keyword}, '%'))
AND x.created_at >= #{from} AND x.created_at <= #{to} ORDER BY x.created_at DESC, x.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM credit_transaction x
INNER JOIN user_account u ON u.id = x.user_id
WHERE 1 = 1
AND x.tenant_id = #{tenantId}
AND x.user_id = #{userId}
AND x.direction = #{direction}

    AND (u.username ILIKE CONCAT('%', #{keyword}, '%')
      OR u.display_name ILIKE CONCAT('%', #{keyword}, '%'))

AND x.created_at >= #{from}
AND x.created_at <= #{to}

SELECT u.id AS userId, u.username AS username, u.display_name AS userDisplayName, u.tenant_id AS tenantId, t.tenant_code AS tenantCode, t.name AS tenantName, a.balance AS balance FROM user_account u INNER JOIN tenant t ON t.id = u.tenant_id INNER JOIN user_credit_account a ON a.user_id = u.id WHERE u.scope_type = 'TENANT' AND u.deleted_at IS NULL AND u.enabled = TRUE AND u.tenant_id = #{tenantId}
AND (u.username ILIKE CONCAT('%', #{keyword}, '%') OR u.display_name ILIKE CONCAT('%', #{keyword}, '%'))
ORDER BY u.created_at DESC, u.id DESC LIMIT #{limit}

SELECT
    (SELECT COUNT(*) FROM user_credit_account a
        WHERE 1 = 1
        AND a.tenant_id = #{tenantId}
        AND a.user_id = #{userId}
    )                                                                                    AS total_accounts,
    COALESCE((SELECT SUM(a.balance) FROM user_credit_account a
        WHERE 1 = 1
        AND a.tenant_id = #{tenantId}
        AND a.user_id = #{userId}
    ), 0)                                                                                AS total_balance,
    COALESCE((SELECT SUM(a.frozen_balance) FROM user_credit_account a
        WHERE 1 = 1
        AND a.tenant_id = #{tenantId}
        AND a.user_id = #{userId}
    ), 0)                                                                                AS total_frozen_balance,
    COALESCE((SELECT SUM(x.delta) FROM credit_transaction x WHERE x.direction = 'CREDIT'
        AND x.tenant_id = #{tenantId}
        AND x.user_id = #{userId}
    ), 0)                                                                                AS total_credits,
    COALESCE((SELECT SUM(x.delta) FROM credit_transaction x WHERE x.direction = 'DEBIT'
        AND x.tenant_id = #{tenantId}
        AND x.user_id = #{userId}
    ), 0)                                                                                AS total_debits,
    (SELECT COUNT(*) FROM credit_transaction x WHERE 1 = 1
        AND x.tenant_id = #{tenantId}
        AND x.user_id = #{userId}
    )                                                                                    AS transaction_count
